bmc_encoding.pseudocode:
function EncodeBMC(G, Safe, start, target, k):
  // Create version variables: x[i][t] = version of service i at step t
  for t in 0..k:
    for i in 1..n:
      x[i][t] = new_bitvector(ceil(log2(L_i)))  // binary encoding

  // Initial and final state constraints
  for i in 1..n:
    assert(x[i][0] == start[i])
    assert(x[i][k] == target[i])

  // Transition relation: exactly one service upgrades by one step
  for t in 0..k-1:
    // Monotone: x[i][t+1] >= x[i][t] for all i
    for i in 1..n:
      assert(x[i][t+1] >= x[i][t])
    // Exactly one service changes
    changed = [x[i][t+1] != x[i][t] for i in 1..n]
    assert(exactly_one(changed))
    // The changed service advances by exactly 1
    for i in 1..n:
      assert(changed[i] => x[i][t+1] == x[i][t] + 1)

  // Safety constraints at each step
  for t in 0..k:
    for (i,j) in Deps:
      assert(Compatible(x[i][t], x[j][t]))  // uses interval encoding

  return formula

interval_encoding.pseudocode:
function EncodeIntervalCompatibility(x_i, x_j, lo, hi):
  // x_i, x_j are bitvector variables (ceil(log2 L) bits)
  // For each possible value v of x_i, compatible versions of x_j form [lo[v], hi[v]]
  // Encode: (x_j >= lo[x_i]) AND (x_j <= hi[x_i])

  // Step 1: Encode lo[x_i] as a multiplexed bitvector
  lo_bits = MuxTree(x_i, lo)  // lo_bits = lo[x_i], O(L·log L) gates
  hi_bits = MuxTree(x_i, hi)  // hi_bits = hi[x_i], O(L·log L) gates

  // Step 2: Binary comparison
  assert(BinaryGEQ(x_j, lo_bits))  // O(log L) clauses
  assert(BinaryLEQ(x_j, hi_bits))  // O(log L) clauses

  // Total: O(L·log L + log L) = O(L·log L) gates
  // But with interval monotonicity of lo/hi, the MuxTree simplifies
  // to O(log²L) via binary decision tree encoding

cegar_loop.pseudocode:
function CEGARSolve(bmc_formula, resource_constraints):
  blocking_clauses = []
  iteration = 0
  while true:
    // Phase 1: Solve compatibility constraints with CaDiCaL
    result = CaDiCaL.solve(bmc_formula + blocking_clauses)
    if result == UNSAT:
      return INFEASIBLE  // No plan satisfies compatibility + all blocking clauses

    // Phase 2: Check resource constraints with Z3
    plan = extract_plan(result.model)
    for t in 0..k:
      state = plan[t]
      if not Z3.check(resource_constraints(state)):
        // Extract minimal conflict
        core = Z3.unsat_core()
        // Generalize: block all plans sharing this resource conflict
        blocking = generalize_blocking_clause(core, result.model)
        blocking_clauses.append(blocking)
        break
    else:
      return plan  // All steps satisfy resources

    iteration += 1
    if iteration > MAX_CEGAR_ITERATIONS:
      return TIMEOUT

envelope_computation.pseudocode:
function ComputeEnvelope(plan, G, Safe, start, target):
  envelope = []
  pnr_states = []

  // Forward reachability is guaranteed (plan is safe by construction)
  // Only need backward reachability to start
  for t in 0..len(plan):
    state = plan[t]

    // Check backward reachability using incremental SAT
    // Key: share clause database across all backward checks
    backward_formula = EncodeBMCBackward(state, start, Safe)

    // Use assumption literals to activate/deactivate per-state constraints
    assumptions = [assume_start(state)]
    result = CaDiCaL.solve_incremental(backward_formula, assumptions)

    if result == SAT:
      envelope.append(t)  // State is in the envelope
    else:
      pnr_states.append(t)
      // Extract stuck-configuration witness
      core = CaDiCaL.unsat_core()
      witness = minimize_core(core)
      annotate_pnr(plan[t], witness)

  return envelope, pnr_states

pairwise_prefilter.pseudocode:
function PairwisePreFilter(start, target, compatibility):
  for (i,j) in Deps:
    // Check if any compatible path exists for this pair alone
    reachable_i = versions between start[i] and target[i]
    reachable_j = versions between start[j] and target[j]
    for v in reachable_i:
      compatible_found = false
      for w in reachable_j:
        if compatibility[i][j][v][w]:
          compatible_found = true
          break
      if not compatible_found:
        return INFEASIBLE(i, j, v)  // No version of j compatible with i@v
  return POSSIBLY_FEASIBLE

k_robustness.pseudocode:
function KRobustnessCheck(plan, red_constraints, k):
  failures = []
  for subset in combinations(red_constraints, k):
    // Flip each constraint in subset to incompatible
    modified_safe = Safe with subset flipped
    // Check if plan is still safe under modified constraints
    for t in 0..len(plan):
      if plan[t] not in modified_safe:
        failures.append((subset, t))
        break

  if len(failures) == 0:
    return ROBUST(k)
  else:
    return VULNERABLE(failures)
